 32â†’// GetByID returns a single item by ID and owner. Returns nil, nil if not found.
 33â†’func (s *Service) GetByID(ctx context.Context, ownerID, itemID uuid.UUID) (*Item, error) {
 34â†’	query := fmt.Sprintf(`SELECT %s FROM items WHERE owner_id = $1 AND id = $2`, itemColumns)
 35â†’	row := s.pool.QueryRow(ctx, query, ownerID, itemID)
 36â†’	it, err := scanItem(row)
 37â†’	if errors.Is(err, pgx.ErrNoRows) {
 38â†’		return nil, nil
 39â†’	}
 40â†’	if err != nil {
 41â†’		return nil, fmt.Errorf("item: get by id: %w", err)
 42â†’	}
 43â†’	return it, nil
 44â†’}
