 46â†’// List returns a page of items matching the given filter, sorted and paginated.
 47â†’func (s *Service) List(ctx context.Context, ownerID uuid.UUID, filter *Filter, limit, offset int, sort *Sort) (*SearchResult, error) {
 48â†’	limit = clampLimit(limit, maxLimit)
 49â†’	offset = clampOffset(offset)
 50â†’
 51â†’	qb := &queryBuilder{}
 52â†’	qb.add("owner_id = $%d", ownerID)
 53â†’	applyFilter(qb, filter)
 54â†’	whereClause := qb.where()
 55â†’
 56â†’	// Count total
 57â†’	countQuery := fmt.Sprintf("SELECT COUNT(*) FROM items %s", whereClause)
 58â†’	var total int
 59â†’	if err := s.pool.QueryRow(ctx, countQuery, qb.args...).Scan(&total); err != nil {
 60â†’		return nil, fmt.Errorf("item: list count: %w", err)
 61â†’	}
 62â†’
 63â†’	// Determine sort
 64â†’	orderCol := "created_at"
 65â†’	orderDir := "DESC"
 66â†’	if sort != nil {
 67â†’		if col, ok := sortFieldToColumn(sort.Field); ok {
 68â†’			orderCol = col
 69â†’		}
 70â†’		orderDir = sortDirectionSQL(sort.Direction)
 71â†’	}
 72â†’
 73â†’	dataQuery := fmt.Sprintf(`SELECT %s FROM items %s ORDER BY %s %s LIMIT $%d OFFSET $%d`,
 74â†’		itemColumns, whereClause, orderCol, orderDir, qb.nextParam(), qb.nextParam()+1)
 75â†’	qb.args = append(qb.args, limit, offset)
 76â†’
 77â†’	rows, err := s.pool.Query(ctx, dataQuery, qb.args...)
 78â†’	if err != nil {
 79â†’		return nil, fmt.Errorf("item: list query: %w", err)
 80â†’	}
 81â†’	defer rows.Close()
 82â†’
 83â†’	items, err := scanItems(rows)
 84â†’	if err != nil {
 85â†’		return nil, fmt.Errorf("item: list scan: %w", err)
 86â†’	}
 87â†’
 88â†’	return &SearchResult{
 89â†’		Items:   items,
 90â†’		Total:   total,
 91â†’		HasMore: offset+len(items) < total,
 92â†’	}, nil
 93â†’}
