 95â†’// Search performs full-text search over items using the search_vector column.
 96â†’func (s *Service) Search(ctx context.Context, ownerID uuid.UUID, query string, filter *Filter, limit int, threshold float64) (*SearchResult, error) {
 97â†’	if query == "" {
 98â†’		return &SearchResult{Items: []*Item{}}, nil
 99â†’	}
100â†’	limit = clampLimit(limit, maxLimit)
101â†’
102â†’	qb := &queryBuilder{}
103â†’	qb.add("owner_id = $%d", ownerID)
104â†’	qb.add("search_vector @@ plainto_tsquery('english', $%d)", query)
105â†’	applyFilter(qb, filter)
106â†’	whereClause := qb.where()
107â†’
108â†’	// Count total matches
109â†’	countQuery := fmt.Sprintf("SELECT COUNT(*) FROM items %s", whereClause)
110â†’	var total int
111â†’	if err := s.pool.QueryRow(ctx, countQuery, qb.args...).Scan(&total); err != nil {
112â†’		return nil, fmt.Errorf("item: search count: %w", err)
113â†’	}
114â†’
115â†’	dataQuery := fmt.Sprintf(
116â†’		`SELECT %s FROM items %s ORDER BY ts_rank(search_vector, plainto_tsquery('english', $2)) DESC LIMIT $%d`,
117â†’		itemColumns, whereClause, qb.nextParam())
118â†’	qb.args = append(qb.args, limit)
119â†’
120â†’	rows, err := s.pool.Query(ctx, dataQuery, qb.args...)
121â†’	if err != nil {
122â†’		return nil, fmt.Errorf("item: search query: %w", err)
123â†’	}
124â†’	defer rows.Close()
125â†’
126â†’	items, err := scanItems(rows)
127â†’	if err != nil {
128â†’		return nil, fmt.Errorf("item: search scan: %w", err)
129â†’	}
130â†’
131â†’	return &SearchResult{
132â†’		Items:   items,
133â†’		Total:   total,
134â†’		HasMore: len(items) < total,
135â†’	}, nil
136â†’}
