138â†’// SemanticSearch finds items similar to the given embedding vector using cosine similarity.
139â†’func (s *Service) SemanticSearch(ctx context.Context, ownerID uuid.UUID, embedding []float32, filter *Filter, limit int, threshold float64) (*SearchResult, error) {
140â†’	if len(embedding) == 0 {
141â†’		return &SearchResult{Items: []*Item{}}, nil
142â†’	}
143â†’	limit = clampLimit(limit, maxLimit)
144â†’
145â†’	vec := pgvector.NewVector(embedding)
146â†’
147â†’	qb := &queryBuilder{}
148â†’	qb.add("owner_id = $%d", ownerID)
149â†’	applyFilter(qb, filter)
150â†’
151â†’	// Add embedding parameters after the filter params
152â†’	embeddingParam := qb.nextParam()
153â†’	qb.args = append(qb.args, vec)
154â†’	thresholdParam := qb.nextParam()
155â†’	qb.args = append(qb.args, threshold)
156â†’
157â†’	whereClause := qb.where()
158â†’	whereClause += fmt.Sprintf(" AND embedding IS NOT NULL AND (1 - (embedding <=> $%d)) >= $%d",
159â†’		embeddingParam, thresholdParam)
160â†’
161â†’	// Count total matches
162â†’	countQuery := fmt.Sprintf("SELECT COUNT(*) FROM items %s", whereClause)
163â†’	var total int
164â†’	if err := s.pool.QueryRow(ctx, countQuery, qb.args...).Scan(&total); err != nil {
165â†’		return nil, fmt.Errorf("item: semantic search count: %w", err)
166â†’	}
167â†’
168â†’	limitParam := qb.nextParam()
169â†’	qb.args = append(qb.args, limit)
170â†’
171â†’	dataQuery := fmt.Sprintf(
172â†’		`SELECT %s FROM items %s ORDER BY embedding <=> $%d LIMIT $%d`,
173â†’		itemColumns, whereClause, embeddingParam, limitParam)
174â†’
175â†’	rows, err := s.pool.Query(ctx, dataQuery, qb.args...)
176â†’	if err != nil {
177â†’		return nil, fmt.Errorf("item: semantic search query: %w", err)
178â†’	}
179â†’	defer rows.Close()
180â†’
181â†’	items, err := scanItems(rows)
182â†’	if err != nil {
183â†’		return nil, fmt.Errorf("item: semantic search scan: %w", err)
184â†’	}
185â†’
186â†’	return &SearchResult{
187â†’		Items:   items,
188â†’		Total:   total,
189â†’		HasMore: len(items) < total,
190â†’	}, nil
191â†’}
