403â†’// UpdateContent updates worker-managed fields (status, title, content) on an item.
404â†’// This is used by background jobs, not exposed via GraphQL.
405â†’func (s *Service) UpdateContent(ctx context.Context, itemID uuid.UUID, input ContentUpdate) error {
406â†’	sets := []string{fmt.Sprintf("status = $%d", 2)}
407â†’	args := []any{itemID, input.Status}
408â†’	paramIdx := 3
409â†’
410â†’	if input.Title != nil {
411â†’		sets = append(sets, fmt.Sprintf("title = $%d", paramIdx))
412â†’		args = append(args, *input.Title)
413â†’		paramIdx++
414â†’	}
415â†’	if input.ContentText != nil {
416â†’		sets = append(sets, fmt.Sprintf("content_text = $%d", paramIdx))
417â†’		args = append(args, *input.ContentText)
418â†’		paramIdx++
419â†’	}
420â†’	if input.ContentURL != nil {
421â†’		sets = append(sets, fmt.Sprintf("content_url = $%d", paramIdx))
422â†’		args = append(args, *input.ContentURL)
423â†’		paramIdx++ //nolint:ineffassign // keeps pattern consistent for future fields
424â†’	}
425â†’
426â†’	query := fmt.Sprintf(`UPDATE items SET %s WHERE id = $1`, joinSets(sets))
427â†’	tag, err := s.pool.Exec(ctx, query, args...)
428â†’	if err != nil {
429â†’		return fmt.Errorf("item: update content: %w", err)
430â†’	}
431â†’	if tag.RowsAffected() == 0 {
432â†’		return fmt.Errorf("item: update content: not found")
433â†’	}
434â†’	return nil
435â†’}
436â†’
437â†’func joinSets(sets []string) string {
438â†’	result := ""
439â†’	for i, s := range sets {
440â†’		if i > 0 {
441â†’			result += ", "
442â†’		}
443â†’		result += s
444â†’	}
445â†’	return result
446â†’}
