  3â†’import (
  4â†’	"fmt"
  5â†’	"strings"
  6â†’)
  7â†’
  8â†’// queryBuilder constructs a dynamic WHERE clause with parameterized conditions.
  9â†’type queryBuilder struct {
 10â†’	conditions []string
 11â†’	args       []any
 12â†’}
 13â†’
 14â†’// add appends a condition with a single parameter. Use %d as the placeholder
 15â†’// position in the condition template (e.g., "type = $%d").
 16â†’func (qb *queryBuilder) add(conditionTemplate string, arg any) {
 17â†’	qb.args = append(qb.args, arg)
 18â†’	qb.conditions = append(qb.conditions, fmt.Sprintf(conditionTemplate, len(qb.args)))
 19â†’}
 20â†’
 21â†’// where returns the WHERE clause string (including "WHERE") or empty string if
 22â†’// no conditions were added.
 23â†’func (qb *queryBuilder) where() string {
 24â†’	if len(qb.conditions) == 0 {
 25â†’		return ""
 26â†’	}
 27â†’	return "WHERE " + strings.Join(qb.conditions, " AND ")
 28â†’}
 29â†’
 30â†’// nextParam returns the next parameter placeholder number without adding a condition.
 31â†’func (qb *queryBuilder) nextParam() int {
 32â†’	return len(qb.args) + 1
 33â†’}
 34â†’
 35â†’// sortFieldToColumn maps GraphQL sort field names to database column names.
 36â†’// Returns the column name and true if valid, or empty string and false if not.
 37â†’func sortFieldToColumn(field string) (string, bool) {
 38â†’	switch strings.ToUpper(field) {
 39â†’	case "CREATED_AT":
 40â†’		return "created_at", true
 41â†’	case "UPDATED_AT":
 42â†’		return "updated_at", true
 43â†’	case "CAPTURED_AT":
 44â†’		return "captured_at", true
 45â†’	case "TITLE":
 46â†’		return "title", true
 47â†’	default:
 48â†’		return "", false
 49â†’	}
 50â†’}
 51â†’
 52â†’// sortDirectionSQL returns "ASC" or "DESC". Defaults to "DESC" for invalid input.
 53â†’func sortDirectionSQL(dir string) string {
 54â†’	if strings.ToUpper(dir) == "ASC" {
 55â†’		return "ASC"
 56â†’	}
 57â†’	return "DESC"
 58â†’}
 59â†’
 60â†’// applyFilter adds filter conditions to the query builder.
 61â†’func applyFilter(qb *queryBuilder, f *Filter) {
 62â†’	if f == nil {
 63â†’		return
 64â†’	}
 65â†’	if len(f.Types) == 1 {
 66â†’		qb.add("type = $%d", f.Types[0])
 67â†’	} else if len(f.Types) > 1 {
 68â†’		qb.add("type = ANY($%d)", f.Types)
 69â†’	}
 70â†’	if len(f.Status) == 1 {
 71â†’		qb.add("status = $%d", f.Status[0])
 72â†’	} else if len(f.Status) > 1 {
 73â†’		qb.add("status = ANY($%d)", f.Status)
 74â†’	}
 75â†’	if len(f.Sensitivity) == 1 {
 76â†’		qb.add("sensitivity = $%d", f.Sensitivity[0])
 77â†’	} else if len(f.Sensitivity) > 1 {
 78â†’		qb.add("sensitivity = ANY($%d)", f.Sensitivity)
 79â†’	}
 80â†’	if len(f.Tags) > 0 {
 81â†’		qb.add("tags && $%d", f.Tags)
 82â†’	}
 83â†’	if f.Source != nil {
 84â†’		qb.add("source = $%d", *f.Source)
 85â†’	}
 86â†’	if f.DateFrom != nil {
 87â†’		qb.add("created_at >= $%d", *f.DateFrom)
 88â†’	}
 89â†’	if f.DateTo != nil {
 90â†’		qb.add("created_at <= $%d", *f.DateTo)
 91â†’	}
 92â†’}
 93â†’
 94â†’// clampLimit ensures limit is between 1 and maxLimit.
 95â†’func clampLimit(limit, maxLimit int) int {
 96â†’	if limit <= 0 {
 97â†’		return 20
 98â†’	}
 99â†’	if limit > maxLimit {
100â†’		return maxLimit
101â†’	}
102â†’	return limit
103â†’}
104â†’
105â†’// clampOffset ensures offset is non-negative.
106â†’func clampOffset(offset int) int {
107â†’	if offset < 0 {
108â†’		return 0
109â†’	}
110â†’	return offset
111â†’}
