 7â†’// scanItem scans a single row into an Item.
 8â†’func scanItem(row pgx.Row) (*Item, error) {
 9â†’	var it Item
10â†’	err := row.Scan(
11â†’		&it.ID, &it.OwnerID, &it.Type, &it.Status, &it.Sensitivity,
12â†’		&it.Title, &it.ContentText, &it.ContentURL,
13â†’		&it.Tags, &it.Metadata, &it.AutoMetadata,
14â†’		&it.Source, &it.SourceURL,
15â†’		&it.CreatedAt, &it.UpdatedAt, &it.CapturedAt,
16â†’	)
17â†’	if err != nil {
18â†’		return nil, err
19â†’	}
20â†’	return &it, nil
21â†’}
22â†’
23â†’// scanItems scans multiple rows into a slice of Items.
24â†’func scanItems(rows pgx.Rows) ([]*Item, error) {
25â†’	var items []*Item
26â†’	for rows.Next() {
27â†’		var it Item
28â†’		err := rows.Scan(
29â†’			&it.ID, &it.OwnerID, &it.Type, &it.Status, &it.Sensitivity,
30â†’			&it.Title, &it.ContentText, &it.ContentURL,
31â†’			&it.Tags, &it.Metadata, &it.AutoMetadata,
32â†’			&it.Source, &it.SourceURL,
33â†’			&it.CreatedAt, &it.UpdatedAt, &it.CapturedAt,
34â†’		)
35â†’		if err != nil {
36â†’			return nil, err
37â†’		}
38â†’		items = append(items, &it)
39â†’	}
40â†’	if err := rows.Err(); err != nil {
41â†’		return nil, err
42â†’	}
43â†’	if items == nil {
44â†’		items = []*Item{}
45â†’	}
46â†’	return items, nil
47â†’}
