174â†’func containsStr(s, substr string) bool {
175â†’	return len(s) >= len(substr) && containsSubstring(s, substr)
176â†’}
177â†’
178â†’func containsSubstring(s, sub string) bool {
179â†’	for i := 0; i <= len(s)-len(sub); i++ {
180â†’		if s[i:i+len(sub)] == sub {
181â†’			return true
182â†’		}
183â†’	}
184â†’	return false
185â†’}
