12â†’// NewRoutingEmbedder creates a routing embedder. If localProvider is nil,
13â†’// all requests are handled by the default provider.
14â†’func NewRoutingEmbedder(defaultProvider, localProvider Embedder) *RoutingEmbedder {
15â†’	return &RoutingEmbedder{
16â†’		defaultProvider: defaultProvider,
17â†’		localProvider:   localProvider,
18â†’	}
19â†’}
